// Pega dados do item atual
const html = $input.item.json.html_template;
const cid = $input.item.json.contato_id;
const camp = $input.item.json.campanha_nome;
const etapa = $input.item.json.etapa;

// URL de redirect baseada na campanha
const redir = camp.includes('bstech')
  ? encodeURIComponent('https://wa.me/5512988112870?text=Olá, gostaria de conhecer a BSTech.')
  : encodeURIComponent('https://wa.me/5531988633298?text=Olá, gostaria de saber mais sobre os equipamentos.');

const trackingUrl = 'https://n8n.iatars.com.br/webhook/bs-click?cid=' + cid + '&camp=' + camp + '&etapa=' + etapa + '&redir=' + redir;

// Trocar TODOS os links wa.me no CTA button por tracking URL
let updatedHtml = html.replace(
  /href="https:\/\/wa\.me\/[^"]*"/g,
  'href="' + trackingUrl + '"'
);

return { ...$input.item.json, html_template: updatedHtml };

